B4DUI = B4DUI or {}; B4DUI.UI=B4DUI.UI or {}
function B4DUI.UI.CreateFrame(title,w,h) local f=vgui.Create("DFrame"); f:SetSize(w or ScrW()*.72,h or ScrH()*.76); f:Center(); f:SetTitle(""); f:ShowCloseButton(false); f:MakePopup(); f.Paint=function(self,pw,ph) B4DUI.UI.PaintPanel(pw,ph); draw.SimpleText(title or "B4D UI","B4D.Title",24,18,B4DUI.Color("text")); draw.RoundedBox(0,0,58,pw,1,B4DUI.Color("border")) end; local c=f:Add("DButton"); c:SetText("×"); c:SetFont("B4D.Large"); c:SetTextColor(B4DUI.Color("muted")); c:SetSize(44,36); c:SetPos(f:GetWide()-52,12); c.Paint=function() end; c.DoClick=function() f:Close() end; return f end
